@namespace Lumeo

@{
    var context = new CommandContext(
        SearchText,
        EventCallback.Factory.Create<string>(this, OnSearchChanged),
        RegisterItem,
        UnregisterItem,
        VisibleItemCount);
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string SearchText { get; set; } = "";
    private readonly HashSet<string> _items = new();

    private string CssClass => $"flex h-full w-full flex-col overflow-hidden rounded-md bg-popover text-popover-foreground {Class}".Trim();

    // CommandItem tracks its own visibility and calls Register only while visible, Unregister when it's not —
    // so VisibleItemCount reflects the filtered result set, which lets CommandEmpty render only when everything
    // is filtered out.
    private int VisibleItemCount => _items.Count;

    private void RegisterItem(string id)
    {
        if (_items.Add(id)) StateHasChanged();
    }

    private void UnregisterItem(string id)
    {
        if (_items.Remove(id)) StateHasChanged();
    }

    private Task OnSearchChanged(string text)
    {
        SearchText = text;
        StateHasChanged();
        return Task.CompletedTask;
    }

    public record CommandContext(
        string SearchText,
        EventCallback<string> OnSearch,
        Action<string> RegisterItem,
        Action<string> UnregisterItem,
        int VisibleItemCount);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* Only renders when every CommandItem has been filtered out — previously rendered unconditionally so users
   saw the empty text stacked under their matching items. *@
@if (IsVisible)
{
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @if (ChildContent is not null)
        {
            @ChildContent
        }
        else
        {
            <span>@L["Command.NoResults"]</span>
        }
    </div>
}

@code {
    [CascadingParameter] public Command.CommandContext? Context { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsVisible => Context is null || Context.VisibleItemCount == 0;

    private string CssClass => $"py-6 text-center text-sm text-muted-foreground {Class}".Trim();
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (Heading is not null)
    {
        <div class="px-2 py-1.5 text-xs font-medium text-muted-foreground">@Heading</div>
    }
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Heading { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"overflow-hidden p-1 text-foreground {Class}".Trim();
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div class="flex items-center border-b border-border/40 px-3">
    <Blazicon Svg="Lucide.Search" class="mr-2 h-4 w-4 shrink-0 opacity-50" />
    <input type="text"
           class="@CssClass"
           placeholder="@(Placeholder ?? L["Command.Placeholder"])"
           value="@Context.SearchText"
           @oninput="HandleInput"
           @attributes="AdditionalAttributes" />
</div>

@code {
    [CascadingParameter] public Command.CommandContext Context { get; set; } = default!;
    [Parameter] public string? Placeholder { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex h-10 w-full rounded-md bg-transparent py-3 text-sm outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50 {Class}".Trim();

    private async Task HandleInput(ChangeEventArgs e)
    {
        await Context.OnSearch.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@namespace Lumeo
@implements IDisposable

@if (IsVisible)
{
    <button type="button" class="@CssClass" @onclick="OnSelect" @attributes="AdditionalAttributes">
        @ChildContent
        @if (Shortcut is not null)
        {
            <span class="ml-auto flex items-center gap-0.5">
                @foreach (var part in Shortcut.Split('+'))
                {
                    <Kbd>@part.Trim()</Kbd>
                }
            </span>
        }
    </button>
}

@code {
    [CascadingParameter] public Command.CommandContext? Context { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public EventCallback OnSelect { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Shortcut { get; set; }
    [Parameter] public string? FilterValue { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = $"cmd-item-{Guid.NewGuid():N}";
    private bool _registered;

    private bool IsVisible => string.IsNullOrEmpty(Context?.SearchText)
        || string.IsNullOrEmpty(FilterValue)
        || FilterValue.Contains(Context.SearchText, StringComparison.OrdinalIgnoreCase);

    private string CssClass => $"relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none hover:bg-accent hover:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 {Class}".Trim();

    protected override void OnParametersSet()
    {
        // Keep the item registered with the Command context only while it's visible — this is what drives
        // CommandEmpty to render exactly when every item has been filtered out.
        if (IsVisible && !_registered)
        {
            Context?.RegisterItem(_itemId);
            _registered = true;
        }
        else if (!IsVisible && _registered)
        {
            Context?.UnregisterItem(_itemId);
            _registered = false;
        }
    }

    public void Dispose()
    {
        if (_registered) Context?.UnregisterItem(_itemId);
    }
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"max-h-[300px] overflow-y-auto overflow-x-hidden {Class}".Trim();
}

@namespace Lumeo

<div class="@CssClass" role="none" @attributes="AdditionalAttributes"></div>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"-mx-1 h-px bg-border {Class}".Trim();
}
